mapper.select:
SELECT sp.id, s.id AS subjectId, 'SUBJECTIVE' AS cardType, sp.question AS frontText, sp.answer AS backText, sp.explanation, sp.difficulty FROM subjective_problems sp INNER JOIN subject s ON sp.subject_id = s.id WHERE s.name = #{category}
UNION ALL
SELECT lc.id, s.id AS subjectId, 'FLASHCARD' AS cardType, lc.front_text AS frontText, lc.back_text AS backText, lc.explanation, 0 AS difficulty FROM learning_card lc INNER JOIN subject s ON lc.subject_id = s.id WHERE s.name = #{category}
ORDER BY cardType, id
